#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;	
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline T max(const T&x,const T&y){return y<x?x:y;}
template<typename T> inline void chkmin(T&x,const T&w){w<x?x=w:T();}
template<typename T> inline void chkmax(T&x,const T&w){x<w?x=w:T();}
const int N=1e5+10,INF=0x3f3f3f3f;
int buf[N<<7],*ToMe[N],*ToFa[N],*tmp=buf,head[N],des[N<<1],nxt[N<<1|1],cgt,n;
inline void ins(const int &x,const int &y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;nxt[++cgt]=head[y];des[head[y]=cgt]=x;}
namespace TreeCut
{
	int fa[N],top[N],dep[N],siz[N],mxs[N];
	inline void dfs1(const int &u=1,const int &f=0)
	{
		dep[u]=dep[fa[u]=f]+1;mxs[u]=0;siz[u]=1;int mx=0;
		grep(u,i)if(des[i]!=f){int v=des[i];dfs1(v,u);siz[u]+=siz[v];mx<siz[v]?mx=siz[mxs[u]=v]:0;}
	}
	inline void dfs2(const int &u=1,const int &fa=0,const int &tp=1)
	{
		top[u]=tp;if(mxs[u])dfs2(mxs[u],u,tp);
		grep(u,i)if(des[i]!=fa&&des[i]!=mxs[u])dfs2(des[i],u,des[i]);
	}
	inline int Dis(int u,int v)
	{
		int ans=dep[u]+dep[v];
		while(top[u]!=top[v])dep[top[u]]<dep[top[v]]?v=fa[top[v]]:u=fa[top[u]];
		return ans-2*dep[dep[u]<dep[v]?u:v];
	}
}
namespace Divide
{
	using TreeCut::Dis;int siz[N],Mn,Rt,fa[N],mxd[N],RT,Sz;bool vis[N];
	inline void getRt(const int &u,const int &fa=0)
	{
		siz[u]=1;int mx=0;grep(u,i)
		{
			int v=des[i];if(vis[v]||v==fa)continue;
			getRt(v,u);siz[u]+=siz[v];chkmax(mx,siz[v]);
		}
		chkmax(mx,Sz-siz[u]);mx<Mn?Mn=mx,Rt=u:0;
	}
	inline void dfs(const int &u,const int &f=0,const int &dep=0)
	{
		++ToMe[RT][dep];if(fa[RT])++ToFa[RT][Dis(u,fa[RT])];
		grep(u,i)if(des[i]!=f&&!vis[des[i]])dfs(des[i],u,dep+1);
		chkmax(mxd[RT],dep);
	}
	inline void Solve(int u)
	{
//		printf("Solve %d\n",u);
		vis[RT=u]=true;ToFa[u]=tmp;tmp[-1]=mxd[fa[u]]+1;tmp+=mxd[fa[u]]+3;ToMe[u]=tmp;dfs(u);tmp[-1]=mxd[u]+1;tmp+=mxd[u]+3;
		grep(u,i)if(!vis[des[i]]){int v=des[i];Sz=siz[v];Mn=INF;getRt(v);fa[Rt]=u;Solve(Rt);}
	}
	inline void build()
	{
		memset(vis,0,n+5);memset(mxd,0,(n+5)<<2);memset(fa,0,sizeof(fa));
		Mn=INF;Sz=n;getRt(1);Solve(Rt);return;
	}
	inline int qry(int d,int x)
	{
//		rep(1,n,i)printf("%d ",fa[i]);puts("");
		int ans=0,p=x;while(p)
		{
			int D(d-Dis(x,p));if(D>=0&&D<=ToMe[p][-1])ans+=ToMe[p][D];if(!fa[p])break;
//			printf("qaq :: %d %d %d\n",p,ans,D);
			D=d-Dis(x,fa[p]);if(D>=0&&D<=ToFa[p][-1])ans-=ToFa[p][D];p=fa[p];
//			printf("quq :: %d %d %d\n",p,ans,D);
		}
		return ans;
	}
}
inline void Solve()
{
	memset(buf,0,sizeof(buf));
	memset(head,0,(n+5)<<2);cgt=0;tmp=buf+2;++tmp[0];
	n=read();int Q=read();rep(2,n,i)ins(read(),read());
	TreeCut::dfs1();TreeCut::dfs2();Divide::build();
//	printf("Debug :: %d %d\n",ToMe[9][2],ToMe[9][-1]);
	while(Q--)printf("%d\n",Divide::qry(read(),read()));
}
int main(){int T=read();while(T--)Solve();}
